import importlib, sys
mods = ['scripts.smoke.budget_counter', 'scripts.smoke.evidence_extractor', 'scripts.smoke.upload_evidence', 'scripts.smoke.provider_rates', 'scripts.smoke.phase13_live_smoke']
failed = []
for name in mods:
    try:
        importlib.import_module(name)
    except Exception as e:
        failed.append((name, type(e).__name__, str(e)))
if failed:
    for n, et, m in failed:
        sys.stderr.write(f'FAIL {n}: {et}: {m}\n')
    sys.exit(1)
print(f'IMPORT_OK count={len(mods)} 대표님')
